import{_ as a,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Avançado: Fluxos de Trabalho com IA | oh-my-opencode","description":"Domine a orquestração avançada de fluxos de trabalho com IA no oh-my-opencode. Aprenda sobre equipes de agentes, tarefas paralelas, sistema de Categorias/Skills, ganchos de ciclo de vida e personalização profunda para construir sistemas de desenvolvimento com IA eficientes.","frontmatter":{"title":"Avançado: Fluxos de Trabalho com IA | oh-my-opencode","sidebarTitle":"Trabalhe Como uma Equipe","subtitle":"Avançado: Fluxos de Trabalho com IA","description":"Domine a orquestração avançada de fluxos de trabalho com IA no oh-my-opencode. Aprenda sobre equipes de agentes, tarefas paralelas, sistema de Categorias/Skills, ganchos de ciclo de vida e personalização profunda para construir sistemas de desenvolvimento com IA eficientes.","order":60},"headers":[],"relativePath":"pt/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"pt/code-yeongyu/oh-my-opencode/advanced/index.md"}'),n={name:"pt/code-yeongyu/oh-my-opencode/advanced/index.md"};function r(d,e,t,l,c,p){return s(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="avancado" tabindex="-1">Avançado <a class="header-anchor" href="#avancado" aria-label="Permalink to &quot;Avançado&quot;">​</a></h1><p>Este capítulo mergulha profundamente nos recursos avançados do oh-my-opencode: equipes profissionais de agentes de IA, tarefas em segundo plano paralelas, sistema de Categorias e Skills, ganchos de ciclo de vida e mais. Dominar essas capacidades permitirá que você orquestre fluxos de trabalho com IA como gerenciar uma equipe real, alcançando uma experiência de desenvolvimento mais eficiente.</p><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><div class="grid-cards"><h3 id="equipes-de-agentes-de-ia-visao-geral-de-10-especialistas" tabindex="-1"><a href="./ai-agents-overview/">Equipes de Agentes de IA: Visão Geral de 10 Especialistas</a> <a class="header-anchor" href="#equipes-de-agentes-de-ia-visao-geral-de-10-especialistas" aria-label="Permalink to &quot;[Equipes de Agentes de IA: Visão Geral de 10 Especialistas](./ai-agents-overview/)&quot;">​</a></h3><p>Apresentação abrangente da funcionalidade, casos de uso e métodos de chamada dos 10 agentes integrados. Aprenda a selecionar o agente certo com base no tipo de tarefa, permitindo colaboração eficiente de equipe, execução paralela de tarefas e análise profunda de código.</p><h3 id="planejamento-prometheus-coleta-de-requisitos-baseada-em-entrevistas" tabindex="-1"><a href="./prometheus-planning/">Planejamento Prometheus: Coleta de Requisitos Baseada em Entrevistas</a> <a class="header-anchor" href="#planejamento-prometheus-coleta-de-requisitos-baseada-em-entrevistas" aria-label="Permalink to &quot;[Planejamento Prometheus: Coleta de Requisitos Baseada em Entrevistas](./prometheus-planning/)&quot;">​</a></h3><p>Esclareça requisitos e gere planos de trabalho através do modo de entrevista. O Prometheus continuará fazendo perguntas até que os requisitos estejam claros e consultará automaticamente Oracle, Metis e Momus para verificar a qualidade do plano.</p><h3 id="tarefas-paralelas-em-segundo-plano-trabalhe-como-uma-equipe" tabindex="-1"><a href="./background-tasks/">Tarefas Paralelas em Segundo Plano: Trabalhe Como uma Equipe</a> <a class="header-anchor" href="#tarefas-paralelas-em-segundo-plano-trabalhe-como-uma-equipe" aria-label="Permalink to &quot;[Tarefas Paralelas em Segundo Plano: Trabalhe Como uma Equipe](./background-tasks/)&quot;">​</a></h3><p>Explicação detalhada do uso do sistema de gerenciamento de agentes em segundo plano. Aprenda controle de concorrência, polling de tarefas e recuperação de resultados, permitindo que múltiplos agentes de IA lidem com diferentes tarefas simultaneamente, melhorando drasticamente a eficiência do trabalho.</p><h3 id="lsp-e-ast-grep-ferramentas-de-refatoracao-de-codigo" tabindex="-1"><a href="./lsp-ast-tools/">LSP e AST-Grep: Ferramentas de Refatoração de Código</a> <a class="header-anchor" href="#lsp-e-ast-grep-ferramentas-de-refatoracao-de-codigo" aria-label="Permalink to &quot;[LSP e AST-Grep: Ferramentas de Refatoração de Código](./lsp-ast-tools/)&quot;">​</a></h3><p>Introdução ao uso de ferramentas LSP e AST-Grep. Demonstre como implementar análise e operações de código em nível de IDE, incluindo navegação de símbolos, pesquisa de referências e pesquisa de código estruturada.</p><h3 id="categorias-e-skills-composicao-dinamica-de-agentes" tabindex="-1"><a href="./categories-skills/">Categorias e Skills: Composição Dinâmica de Agentes</a> <a class="header-anchor" href="#categorias-e-skills-composicao-dinamica-de-agentes" aria-label="Permalink to &quot;[Categorias e Skills: Composição Dinâmica de Agentes](./categories-skills/)&quot;">​</a></h3><p>Aprenda a usar o sistema de Categorias e Skills para criar sub-agentes especializados. Implemente composição flexível de agentes, atribuindo dinamicamente modelos, ferramentas e habilidades com base nos requisitos da tarefa.</p><h3 id="skills-integrados-automacao-de-navegador-e-especialista-em-git" tabindex="-1"><a href="./builtin-skills/">Skills Integrados: Automação de Navegador e Especialista em Git</a> <a class="header-anchor" href="#skills-integrados-automacao-de-navegador-e-especialista-em-git" aria-label="Permalink to &quot;[Skills Integrados: Automação de Navegador e Especialista em Git](./builtin-skills/)&quot;">​</a></h3><p>Apresentação detalhada dos casos de uso e melhores práticas de três Skills integrados (playwright, frontend-ui-ux, git-master). Acesse rapidamente capacidades profissionais como automação de navegador, design de UI frontend e operações Git.</p><h3 id="ganchos-de-ciclo-de-vida-contexto-automatizado-e-controle-de-qualidade" tabindex="-1"><a href="./lifecycle-hooks/">Ganchos de Ciclo de Vida: Contexto Automatizado e Controle de Qualidade</a> <a class="header-anchor" href="#ganchos-de-ciclo-de-vida-contexto-automatizado-e-controle-de-qualidade" aria-label="Permalink to &quot;[Ganchos de Ciclo de Vida: Contexto Automatizado e Controle de Qualidade](./lifecycle-hooks/)&quot;">​</a></h3><p>Introdução ao uso de 32 ganchos de ciclo de vida. Entenda como automatizar injeção de contexto, recuperação de erros e controle de qualidade, construindo um sistema completo de automação de fluxos de trabalho com IA.</p><h3 id="comandos-slash-fluxos-de-trabalho-predefinidos" tabindex="-1"><a href="./slash-commands/">Comandos Slash: Fluxos de Trabalho Predefinidos</a> <a class="header-anchor" href="#comandos-slash-fluxos-de-trabalho-predefinidos" aria-label="Permalink to &quot;[Comandos Slash: Fluxos de Trabalho Predefinidos](./slash-commands/)&quot;">​</a></h3><p>Introdução ao uso de 6 comandos slash integrados. Incluindo /ralph-loop (loop de correção rápida), /refactor (refatoração de código), /start-work (início de execução de projeto) e outros fluxos de trabalho comuns.</p><h3 id="personalizacao-profunda-de-configuracao-gerenciamento-de-agentes-e-permissoes" tabindex="-1"><a href="./advanced-configuration/">Personalização Profunda de Configuração: Gerenciamento de Agentes e Permissões</a> <a class="header-anchor" href="#personalizacao-profunda-de-configuracao-gerenciamento-de-agentes-e-permissoes" aria-label="Permalink to &quot;[Personalização Profunda de Configuração: Gerenciamento de Agentes e Permissões](./advanced-configuration/)&quot;">​</a></h3><p>Ensine aos usuários personalização profunda de configuração de agentes, configurações de permissões, substituição de modelos e modificações de prompt. Domine capacidades completas de configuração, criando fluxos de trabalho com IA alinhados com padrões da equipe.</p></div><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de Aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de Aprendizado&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Step 1                  Step 2                     Step 3                          Step 4                  │</span></span>
<span class="line"><span>│  Understand AI Agents  →   Master Planning     →   Learn Dynamic Agent     →   Deep Customization      │</span></span>
<span class="line"><span>│  (Basic Concepts)          &amp; Parallel Tasks         Composition                 &amp; Automation             │</span></span>
<span class="line"><span>│                                                      (Advanced Usage)          (Expert Level)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Sequência Recomendada</strong>:</p><ol><li><strong>Comece com Equipes de Agentes de IA</strong>: Entenda as responsabilidades e casos de uso dos 10 agentes—este é o alicerce para entender todo o sistema.</li><li><strong>Depois Aprenda Planejamento e Tarefas Paralelas</strong>: Domine o planejamento Prometheus e o sistema de tarefas em segundo plano—este é o núcleo da colaboração eficiente.</li><li><strong>Em Seguida Aprenda Composição Dinâmica de Agentes</strong>: Aprenda Categorias e Skills para alcançar especialização flexível de agentes.</li><li><strong>Finalmente Aprenda Personalização Profunda</strong>: Domine ganchos de ciclo de vida, comandos slash e personalização de configuração para construir fluxos de trabalho completos.</li></ol><p><strong>Rotas Avançadas</strong>:</p><ul><li>Se seu objetivo é <strong>início rápido</strong>: Foque em &quot;Equipes de Agentes de IA&quot; e &quot;Comandos Slash&quot;</li><li>Se seu objetivo é <strong>colaboração em equipe</strong>: Mergulhe profundamente em &quot;Planejamento Prometheus&quot; e &quot;Tarefas Paralelas em Segundo Plano&quot;</li><li>Se seu objetivo é <strong>automação de fluxos de trabalho</strong>: Aprenda &quot;Ganchos de Ciclo de Vida&quot; e &quot;Personalização Profunda de Configuração&quot;</li></ul><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de Começar</p><p>Este capítulo assume que você completou:</p><ul><li>✅ <a href="./../start/installation/">Instalação Rápida e Configuração</a>: Instalou o oh-my-opencode e configurou pelo menos um Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">Primeiro Olhar no Sisyphus: Orquestrador Principal</a>: Entendeu mecanismos básicos de chamada e delegação de agentes</li><li>✅ <a href="./../platforms/provider-setup/">Configuração de Provider: Claude, OpenAI, Gemini</a>: Configurou pelo menos um AI Provider</li></ul></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar este capítulo, recomendamos continuar com:</p><ul><li><strong><a href="./../faq/troubleshooting/">Diagnósticos de Configuração e Solução de Problemas</a></strong>: Localize e resolva rapidamente problemas quando surgirem.</li><li><strong><a href="./../appendix/configuration-reference/">Referência de Configuração</a></strong>: Visualize o esquema completo do arquivo de configuração e entenda todas as opções de configuração.</li><li><strong><a href="./../appendix/claude-code-compatibility/">Compatibilidade com Claude Code</a></strong>: Aprenda como migrar fluxos de trabalho existentes do Claude Code para o oh-my-opencode.</li></ul>`,15)])])}const h=a(n,[["render",r]]);export{m as __pageData,h as default};
